import { dnaToKnot, knotToDna, PackedKnot } from './packed-knot';
import { PackedSequenceCodec } from '../../../dash/src/engine/alphabet-codec';
import { MAGIC } from '../lexicon';

/**
 * DNA Reduction Benchmark (V1/V2 vs V3)
 * 
 * Compares the existing AlphabetCodec (AW) with the new Gnosis DNA (DN) format.
 */

// Test data from open-source genomic-topology.test.ts
const TP53 = '';
const KRAS = 'ATGACTGAATATAAACTTGTGGTAGTTGGAGCTGGTGGCGTAGGCAAGAGTGCCTTGACGATACAGCTAATTCAGAATCATTTTGTGGACGAATATGATCCAACAATAGAGGATTCCTACAGGAAGCAAGTAGTAAT';
const POLY_A = 'A'.repeat(1000); // Massive RLE win

const codec = new PackedSequenceCodec();

function benchmark(name: string, dna: string) {
  const rawSize = dna.length;
  
  // V1/V2 (AlphabetCodec)
  const v1v2Bytes = codec.encode({
    kind: 'packed-sequence',
    alphabet: 'dna',
    sequence: dna
  });
  
  // V3 (Gnosis DNA)
  const knot = dnaToKnot(dna);
  const v3Bytes = knotToBytes(knot, MAGIC.DNA); // Using our new surface-aware toBytes
  
  const reduction = ((v1v2Bytes.length - v3Bytes.length) / v1v2Bytes.length) * 100;
  
  console.log(`[${name}]`);
  console.log(`  Raw:    ${rawSize} bytes`);
  console.log(`  V1/V2:  ${v1v2Bytes.length} bytes`);
  console.log(`  V3 DNA: ${v3Bytes.length} bytes`);
  console.log(`  Gain:   ${reduction.toFixed(2)}% reduction over V2`);
  console.log('');
}

